import{bQ as d,aL as a,u as e,G as r}from"./chunks/framework.D06dwy5q.js";const s=JSON.parse('{"title":"企业架构形态","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/14-企业架构形态.md","filePath":"00.互联网与架构基础/14-企业架构形态.md","lastUpdated":null}'),h={name:"00.互联网与架构基础/14-企业架构形态.md"};function p(o,t,i,l,b,n){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="企业架构形态" tabindex="-1">企业架构形态 <a class="header-anchor" href="#企业架构形态" aria-label="Permalink to &quot;企业架构形态&quot;">​</a></h1><p>公司里的系统不会都长一个样。内部小工具可能一台机器就够，核心交易系统可能要多机房、高可用、灰度发布、审计和容灾。</p><p>这些形态通常不是一开始就设计得很复杂，而是业务量、团队规模、可用性要求和历史包袱一起推出来的。单机、主备、集群、读写分离、缓存、消息队列、微服务、容器化，都对应某类具体问题。</p><h2 id="一、单机" tabindex="-1">一、单机 <a class="header-anchor" href="#一、单机" aria-label="Permalink to &quot;一、单机&quot;">​</a></h2><p>单机形态把入口、应用和数据库放在一台服务器或少量服务器上。</p><p>适合：</p><table tabindex="0"><thead><tr><th>场景</th><th>说明</th></tr></thead><tbody><tr><td>内部小工具</td><td>用户少，停机影响可控</td></tr><tr><td>早期系统</td><td>功能还在验证</td></tr><tr><td>临时平台</td><td>生命周期短，重点是快速交付</td></tr></tbody></table><p>单机的好处是清楚。缺点是机器故障、磁盘满、误操作都会直接影响业务。即使是单机，也要有备份、监控和重建记录。</p><h2 id="二、主备" tabindex="-1">二、主备 <a class="header-anchor" href="#二、主备" aria-label="Permalink to &quot;二、主备&quot;">​</a></h2><p>主备形态用一主一备处理关键组件高可用。主节点工作，备节点等待接管。</p><p>常见对象：</p><table tabindex="0"><thead><tr><th>对象</th><th>主备方式</th></tr></thead><tbody><tr><td>数据库</td><td>主库写入，从库同步，故障时提升从库</td></tr><tr><td>负载均衡</td><td>Keepalived + VIP 漂移</td></tr><tr><td>文件服务</td><td>主备存储或同步复制</td></tr></tbody></table><p>主备的核心是切换。手工切换要有清晰步骤，自动切换要有防脑裂机制。切换后还要处理旧主恢复、数据补齐和客户端连接刷新。</p><h2 id="三、集群" tabindex="-1">三、集群 <a class="header-anchor" href="#三、集群" aria-label="Permalink to &quot;三、集群&quot;">​</a></h2><p>集群用多个节点共同提供能力。Web 应用集群最常见，多个实例挂在负载均衡后面。缓存、消息队列、搜索、数据库也有自己的集群模型。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20App1%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%22%5D%0A%20%20App2%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%22%5D%0A%20%20Cache%5B%22Redis%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%E4%B8%BB%E4%BB%8E%22%5D%0A%20%20MQ%5B%22%E6%B6%88%E6%81%AF%E9%98%9F%E5%88%97%22%5D%0A%0A%20%20User%20--%3E%20LB%0A%20%20LB%20--%3E%20App1%0A%20%20LB%20--%3E%20App2%0A%20%20App1%20--%3E%20Cache%0A%20%20App2%20--%3E%20Cache%0A%20%20App1%20--%3E%20DB%0A%20%20App2%20--%3E%20DB%0A%20%20App1%20--%3E%20MQ%0A"></div><p>集群的关键是多个节点之间如何分工：每个节点都能处理任意请求，还是数据分片到不同节点；入口能不能自动摘除故障节点，还是需要人工处理。</p><h2 id="四、读写分离" tabindex="-1">四、读写分离 <a class="header-anchor" href="#四、读写分离" aria-label="Permalink to &quot;四、读写分离&quot;">​</a></h2><p>数据库读写分离把写请求交给主库，读请求分给从库。它适合读多写少的场景。</p><p>读写分离会带来复制延迟。用户刚提交一条记录，马上去列表查询，如果读请求打到延迟的从库，可能看不到刚写入的数据。</p><p>常见处理方式：</p><table tabindex="0"><thead><tr><th>场景</th><th>做法</th></tr></thead><tbody><tr><td>写后立刻读</td><td>短时间内读主库</td></tr><tr><td>普通查询</td><td>读从库分摊压力</td></tr><tr><td>报表查询</td><td>走专门的只读库或离线数据</td></tr></tbody></table><p>读写分离也有成本。SQL、连接池、中间件、延迟监控和故障切换都要一起考虑。</p><h2 id="五、分库分表" tabindex="-1">五、分库分表 <a class="header-anchor" href="#五、分库分表" aria-label="Permalink to &quot;五、分库分表&quot;">​</a></h2><p>单表数据量太大或单库写入压力太高时，会出现分库分表。它把数据按某个规则拆到不同表或不同库里。</p><p>常见拆分依据：</p><table tabindex="0"><thead><tr><th>方式</th><th>示例</th></tr></thead><tbody><tr><td>按用户 ID</td><td>用户 1 到库 A，用户 2 到库 B</td></tr><tr><td>按时间</td><td>每月一张表，每年一个库</td></tr><tr><td>按业务</td><td>订单库、支付库、用户库分开</td></tr></tbody></table><p>分库分表能分散压力，也会让查询更复杂。跨库事务、跨分片查询、分页、统计和扩容迁移都会变难。很多系统会先用索引、归档、缓存、读写分离撑住，再考虑分片。</p><h2 id="六、缓存和消息队列" tabindex="-1">六、缓存和消息队列 <a class="header-anchor" href="#六、缓存和消息队列" aria-label="Permalink to &quot;六、缓存和消息队列&quot;">​</a></h2><p>缓存通常放在数据库前面，减少重复查询。消息队列通常放在服务之间，让耗时任务异步执行。</p><p>典型场景：</p><table tabindex="0"><thead><tr><th>组件</th><th>解决的问题</th></tr></thead><tbody><tr><td>Redis 缓存</td><td>热点数据读压力</td></tr><tr><td>Redis 锁</td><td>控制并发修改</td></tr><tr><td>RabbitMQ</td><td>后台任务、可靠投递</td></tr><tr><td>Kafka</td><td>大吞吐日志、事件流</td></tr></tbody></table><p>引入缓存后要处理数据一致性，引入消息队列后要处理重复消费、失败重试和任务积压。组件越多，系统吞吐和解耦能力更强，排查路径也更长。</p><h2 id="七、服务治理" tabindex="-1">七、服务治理 <a class="header-anchor" href="#七、服务治理" aria-label="Permalink to &quot;七、服务治理&quot;">​</a></h2><p>服务数量多以后，需要治理服务之间的调用。</p><p>常见能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>作用</th></tr></thead><tbody><tr><td>服务发现</td><td>服务名找到实例地址</td></tr><tr><td>配置中心</td><td>统一管理配置</td></tr><tr><td>限流熔断</td><td>防止故障扩散</td></tr><tr><td>链路追踪</td><td>看清一次请求跨了哪些服务</td></tr><tr><td>API 网关</td><td>统一入口、认证、审计和限流</td></tr></tbody></table><p>企业架构形态可以从一条请求看出来：入口在哪里，应用有几层，状态放在哪里，异步任务如何处理，数据库如何扩展，故障时哪一层能接住。</p>',38)])])}const E=d(h,[["render",p]]);export{s as __pageData,E as default};
